import{_ as a,c as i,o as l,aN as n}from"./chunks/framework.CMIDsdwV.js";const u=JSON.parse('{"title":"OpenClaw 接入飞书","description":"","frontmatter":{"title":"OpenClaw 接入飞书","date":"2026-03-08","permalink":"/aigc/development/open-claw/feishu","tags":["AI应用开发","OpenClaw"],"categories":["AI应用开发","OpenClaw"]},"headers":[],"relativePath":"AIGC/AI应用开发/03.OpenClaw/3_OpenClaw接入飞书.md","filePath":"AIGC/AI应用开发/03.OpenClaw/3_OpenClaw接入飞书.md","lastUpdated":1772964755000}'),s={name:"AIGC/AI应用开发/03.OpenClaw/3_OpenClaw接入飞书.md"};function p(t,e,o,r,h,d){return l(),i("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /AIGC\\AI应用开发\\03.OpenClaw\\3_OpenClaw接入飞书.md for this page in Markdown format</div><h1 id="openclaw-接入飞书" tabindex="-1">OpenClaw 接入飞书 <a class="header-anchor" href="#openclaw-接入飞书" aria-label="Permalink to &quot;OpenClaw 接入飞书&quot;">​</a></h1><h2 id="一、创建飞书机器人" tabindex="-1">一、创建飞书机器人 <a class="header-anchor" href="#一、创建飞书机器人" aria-label="Permalink to &quot;一、创建飞书机器人&quot;">​</a></h2><p>进入飞书开放平台：</p><p><a href="https://open.feishu.cn" target="_blank" rel="noreferrer">https://open.feishu.cn</a></p><p>操作流程：</p><ol><li>登录账号，进入开发者后台，<a href="https://open.feishu.cn/app" target="_blank" rel="noreferrer">https://open.feishu.cn/app</a></li><li>创建企业自建应用</li><li>添加机器人能力</li><li>在权限管理中搜索 <code>im:</code> 并开通消息相关权限</li><li>创建版本并发布，版本号1.0.0</li></ol><p>机器人创建完成。</p><h2 id="二、连接-openclaw-和飞书" tabindex="-1">二、连接 OpenClaw 和飞书 <a class="header-anchor" href="#二、连接-openclaw-和飞书" aria-label="Permalink to &quot;二、连接 OpenClaw 和飞书&quot;">​</a></h2><p>回到 PowerShell，输入：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>配置流程：</p><ol><li>Where will the Gateway run：选择 local</li><li>Select sections to configure：选择 Channels</li><li>Channels：选择 Configure/link</li><li>Select a channel：选择 Feishu</li><li>Install Feishu plugin：通过 npm 安装插件</li><li>How do you want to provide this App Secret：选择 Enter App Secret</li><li>输入飞书 App Secret 及 App ID，在飞书应用【凭证与基础信息】中获取</li><li>Feishu connection mode：通讯方式选择 WebSocket 实时通讯</li><li>Which Feishu domain：域名选择国内版 feishu.cn</li><li>Group chat policy：群聊权限选择 Open，在所有群里都可以使用机器人，但必须@机器人</li><li>Select a channel：选择 Finished</li><li>Configure DM access policies now：私聊策略选择 Yes</li><li>Feishu DM policy：自己用选择 Open 不需要配对，正式环境选择 Pairing</li><li>Select sections to configure：选择 Continue</li></ol><p>完成后运行：</p><p>如果 OpenClaw 已在运行先停止</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>启动</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="三、飞书事件配置" tabindex="-1">三、飞书事件配置 <a class="header-anchor" href="#三、飞书事件配置" aria-label="Permalink to &quot;三、飞书事件配置&quot;">​</a></h2><p>在飞书开发者后台的机器人应用：</p><p>进入事件与回调</p><p>订阅方式选择：长连接</p><p>添加事件：接收消息</p><p>然后在权限管理中新增权限：获取通讯录基本信息</p><p>最后创建新版本并发布。</p><h2 id="四、测试机器人" tabindex="-1">四、测试机器人 <a class="header-anchor" href="#四、测试机器人" aria-label="Permalink to &quot;四、测试机器人&quot;">​</a></h2><p>打开飞书 App。</p><p>在消息列表中找到刚创建的应用，发送一条消息。</p><p>如果 OpenClaw 能正常回复，说明配置成功。</p><p>现在你可以：</p><ul><li>在私聊中与机器人对话</li><li>在群聊中 @机器人</li><li>让它执行自动化任务</li></ul><p>撒花 🎉</p>',32)])])}const k=a(s,[["render",p]]);export{u as __pageData,k as default};
